#include <bits/stdc++.h>
#define zrq0331
#define int long long
using namespace std;
int n , m;
int a[10000005], b[10000005], c[10000005];
int o;
int tot, tot1;
int ans;
void dfs (int p, int sum) {
	if (p == o + 1) {
		b[++tot] = sum;
		return;
	}
	dfs (p + 1, sum);
	if (sum + a[p] <= m) {
		dfs (p + 1, sum + a[p]);
	}
}
void dfs1 (int p, int sum) {
	if (p == n + 1) {
		c[++tot1] = sum;
		return;
	}
	dfs1 (p + 1, sum);
	if (sum + a[ p ] <= m) {
		dfs1 (p + 1, sum + a[p]);
	}
}
signed main() {
	cin >> n >> m;
	for (int i = 1; i <= n; i++) {
		cin >> a[ i ];
	}
	o = n / 2;
	dfs (1, 0);
	sort (b + 1, b + tot + 1);
	dfs1 (o + 1, 0);
	sort (c + 1, c + tot1 + 1);
	int l = tot1;
	for (int i = 1; i <= tot; i++) {
		while (l && b[i] + c[l] > m) {
			l--;
		}
		ans += l; 
	}
	cout << ans;
	return 0;
}
